import React, { useEffect, useRef, useState, forwardRef, useImperativeHandle } from 'react';
import {
  Stage,
  Layer,
  Group,
  Image as KonvaImage,
  Rect,
  Line,
  Circle,
  Ellipse,
  Arrow,
  Transformer,
  Label,
  Tag,
  Text,
} from 'react-konva';
import './AnnotationCanvas.css';

export default forwardRef(function AnnotationCanvas(
  {
    fileUrl,
    annotations,
    onAnnotationsChange,
    selectedTool,
    scale,
    onWheelZoom,
    activeLabelColor,
    labelClasses,
    onFinishShape,
    onDeleteAnnotation,
    activeLabel,
    segmentationType,
  },
  ref
) {
  const stageRef = useRef(null);
  const containerRef = useRef(null);

  const [dims, setDims] = useState({ width: 0, height: 0 });
  const [konvaImg, setKonvaImg] = useState(null);

  // Master group offset (image panning)
  const [imagePos, setImagePos] = useState({ x: 0, y: 0 });

  // In-progress shapes (while drawing)
  const [newBox, setNewBox] = useState(null);
  const [tempPoints, setTempPoints] = useState([]);
  const [drawingPolygon, setDrawingPolygon] = useState(false);
  const [tempPolyline, setTempPolyline] = useState([]);
  const [drawingPolyline, setDrawingPolyline] = useState(false);
  const [newEllipse, setNewEllipse] = useState(null);

  // Points annotation
  const [tempPointPoints, setTempPointPoints] = useState([]);
  const [drawingPoint, setDrawingPoint] = useState(false);

  // Instance segmentation polygon
  const [tempInstancePoints, setTempInstancePoints] = useState([]);
  const [drawingInstancePolygon, setDrawingInstancePolygon] = useState(false);

  // Semantic segmentation polygon
  const [tempSemanticPoints, setTempSemanticPoints] = useState([]);
  const [drawingSemanticPolygon, setDrawingSemanticPolygon] = useState(false);

  // For selecting shape to transform (only for bbox & ellipse)
  const [selectedAnnotationIndex, setSelectedAnnotationIndex] = useState(null);
  const transformerRef = useRef(null);

  // We'll store refs only for shapes that can be transformed: bbox, ellipse
  const shapeRefs = useRef([]);

  // Track last click time for double-click (finish polygon/polyline)
  const lastClickTimeRef = useRef(0);
  const doubleClickThreshold = 250; // ms

  // For copy/paste
  const [copiedAnnotation, setCopiedAnnotation] = useState(null);

  // Instance counters for instance segmentation
  const [instanceCounters, setInstanceCounters] = useState({});

  // ----------- Window / container sizing -----------
  useEffect(() => {
    const handleResize = () => {
      if (!containerRef.current) return;
      setDims({
        width: containerRef.current.offsetWidth,
        height: containerRef.current.offsetHeight,
      });
    };
    window.addEventListener('resize', handleResize);
    handleResize();
    return () => window.removeEventListener('resize', handleResize);
  }, []);

  // ----------- Load image -----------
  useEffect(() => {
    if (!fileUrl) return;
    const img = new window.Image();
    img.src = fileUrl;
    img.onload = () => {
      setKonvaImg(img);
      setImagePos({ x: 0, y: 0 });
    };
    img.onerror = () => console.error('Could not load image:', fileUrl);
  }, [fileUrl]);

  // ----------- Flatten points helper -----------
  function flattenPoints(pts) {
    return pts.flatMap((p) => [p.x, p.y]);
  }

  // ----------- Color shading for instance polygons -----------
  function shadeColor(col, amt) {
    let usePound = false;
    let color = col;
    if (color[0] === '#') {
      color = color.slice(1);
      usePound = true;
    }
    let R = parseInt(color.substring(0, 2), 16);
    let G = parseInt(color.substring(2, 4), 16);
    let B = parseInt(color.substring(4, 6), 16);

    R = Math.min(255, Math.max(0, R + amt));
    G = Math.min(255, Math.max(0, G + amt));
    B = Math.min(255, Math.max(0, B + amt));

    const RR = (R.toString(16).length === 1) ? '0' + R.toString(16) : R.toString(16);
    const GG = (G.toString(16).length === 1) ? '0' + G.toString(16) : G.toString(16);
    const BB = (B.toString(16).length === 1) ? '0' + B.toString(16) : B.toString(16);

    return (usePound ? '#' : '') + RR + GG + BB;
  }

  // ----------- Relative pointer position -----------
  function getGroupPos(evt) {
    const group = stageRef.current?.findOne('#anno-group');
    return group ? group.getRelativePointerPosition() : null;
  }

  // ----------- shapeBoundingBox (for labels, etc.) -----------
  function shapeBoundingBox(ann) {
    if (ann.type === 'bbox') {
      return {
        x1: ann.x,
        y1: ann.y,
        x2: ann.x + ann.width,
        y2: ann.y + ann.height,
      };
    } else if (ann.type === 'ellipse') {
      return {
        x1: ann.x - ann.radiusX,
        y1: ann.y - ann.radiusY,
        x2: ann.x + ann.radiusX,
        y2: ann.y + ann.radiusY,
      };
    } else if (ann.type === 'polygon' || ann.type === 'polyline') {
      let minX = Infinity, minY = Infinity, maxX = -Infinity, maxY = -Infinity;
      ann.points.forEach((pt) => {
        if (pt.x < minX) minX = pt.x;
        if (pt.y < minY) minY = pt.y;
        if (pt.x > maxX) maxX = pt.x;
        if (pt.y > maxY) maxY = pt.y;
      });
      return { x1: minX, y1: minY, x2: maxX, y2: maxY };
    } else if (ann.type === 'point') {
      return {
        x1: ann.x,
        y1: ann.y,
        x2: ann.x,
        y2: ann.y,
      };
    } else if (ann.type === 'points') {
      let minX = Infinity,
        minY = Infinity,
        maxX = -Infinity,
        maxY = -Infinity;
      ann.points.forEach((pt) => {
        if (pt.x < minX) minX = pt.x;
        if (pt.y < minY) minY = pt.y;
        if (pt.x > maxX) maxX = pt.x;
        if (pt.y > maxY) maxY = pt.y;
      });
      return { x1: minX, y1: minY, x2: maxX, y2: maxY };
    }
    return null;
  }

  // -------------- Clipping / bounding helpers --------------
  function isOutsideImage(ann) {
    if (!konvaImg) return false;
    const box = shapeBoundingBox(ann);
    if (!box) return false;
    const { x1, y1, x2, y2 } = box;
    if (x2 < 0 || x1 > konvaImg.width || y2 < 0 || y1 > konvaImg.height) {
      return true;
    }
    return false;
  }

  function clipPolygonToRect(points, w, h) {
    const clipRectEdges = [
      { side: 'left', x: 0 },
      { side: 'right', x: w },
      { side: 'top', y: 0 },
      { side: 'bottom', y: h },
    ];

    let outputList = points;

    clipRectEdges.forEach((edge) => {
      const inputList = outputList;
      outputList = [];
      if (inputList.length === 0) return;

      for (let i = 0; i < inputList.length; i++) {
        const current = inputList[i];
        const prev = inputList[(i + inputList.length - 1) % inputList.length];

        const currentInside = isInside(current, edge);
        const prevInside = isInside(prev, edge);

        if (prevInside && currentInside) {
          outputList.push(current);
        } else if (prevInside && !currentInside) {
          const inter = computeIntersection(prev, current, edge);
          if (inter) outputList.push(inter);
        } else if (!prevInside && currentInside) {
          const inter = computeIntersection(prev, current, edge);
          if (inter) outputList.push(inter);
          outputList.push(current);
        }
      }
    });

    return outputList;

    function isInside(pt, edge) {
      if (edge.side === 'left') return pt.x >= edge.x;
      if (edge.side === 'right') return pt.x <= edge.x;
      if (edge.side === 'top') return pt.y >= edge.y;
      if (edge.side === 'bottom') return pt.y <= edge.y;
      return true;
    }

    function computeIntersection(a, b, edge) {
      const dx = b.x - a.x;
      const dy = b.y - a.y;
      let t;
      if (edge.side === 'left' || edge.side === 'right') {
        if (Math.abs(dx) < 1e-8) return null;
        t = (edge.x - a.x) / dx;
        const y = a.y + t * dy;
        return { x: edge.x, y };
      } else {
        if (Math.abs(dy) < 1e-8) return null;
        t = (edge.y - a.y) / dy;
        const x = a.x + t * dx;
        return { x, y: edge.y };
      }
    }
  }

  function clipPolylineToRect(points, w, h) {
    const resultSegments = [];
    for (let i = 0; i < points.length - 1; i++) {
      const p1 = points[i];
      const p2 = points[i + 1];
      const clippedSeg = clipSegmentToRect(p1, p2, w, h);
      if (clippedSeg && clippedSeg.length === 2) {
        if (
          resultSegments.length > 0 &&
          samePoint(resultSegments[resultSegments.length - 1], clippedSeg[0])
        ) {
          resultSegments.push(clippedSeg[1]);
        } else {
          resultSegments.push(clippedSeg[0], clippedSeg[1]);
        }
      }
    }
    const cleaned = [];
    for (let i = 0; i < resultSegments.length; i++) {
      if (i === 0 || !samePoint(resultSegments[i], resultSegments[i - 1])) {
        cleaned.push(resultSegments[i]);
      }
    }
    return cleaned;

    function samePoint(a, b) {
      return Math.abs(a.x - b.x) < 1e-8 && Math.abs(a.y - b.y) < 1e-8;
    }
  }

  function clipSegmentToRect(p1, p2, w, h) {
    let [x1, y1, x2, y2] = [p1.x, p1.y, p2.x, p2.y];
    let t0 = 0;
    let t1 = 1;
    const dx = x2 - x1;
    const dy = y2 - y1;

    function clip(p, q) {
      if (Math.abs(p) < 1e-8) {
        if (q < 0) return false;
        return true;
      }
      const r = q / p;
      if (p < 0) {
        if (r > t1) return false;
        if (r > t0) t0 = r;
      } else if (p > 0) {
        if (r < t0) return false;
        if (r < t1) t1 = r;
      }
      return true;
    }

    if (!clip(-dx, x1)) return null;
    if (!clip(dx, w - x1)) return null;
    if (!clip(-dy, y1)) return null;
    if (!clip(dy, h - y1)) return null;

    if (t1 < t0) return null;

    const nx1 = x1 + t0 * dx;
    const ny1 = y1 + t0 * dy;
    const nx2 = x1 + t1 * dx;
    const ny2 = y1 + t1 * dy;

    return [
      { x: nx1, y: ny1 },
      { x: nx2, y: ny2 },
    ];
  }

  function clampPointToRect(pt, w, h) {
    return {
      x: Math.max(0, Math.min(w, pt.x)),
      y: Math.max(0, Math.min(h, pt.y)),
    };
  }

  function clampBoundingBox(bbox, w, h) {
    let { x, y, width, height } = bbox;

    if (width < 0) {
      x = x + width;
      width = Math.abs(width);
    }
    if (height < 0) {
      y = y + height;
      height = Math.abs(height);
    }

    if (x < 0) {
      width += x;
      x = 0;
    }
    if (y < 0) {
      height += y;
      y = 0;
    }
    if (x + width > w) {
      width = w - x;
    }
    if (y + height > h) {
      height = h - y;
    }

    if (width <= 0 || height <= 0) return null;
    return { ...bbox, x, y, width, height };
  }

  function clampEllipse(ellipse, w, h) {
    const { x, y, radiusX, radiusY } = ellipse;
    let newRx = Math.abs(radiusX);
    let newRy = Math.abs(radiusY);

    const left = x - newRx;
    if (left < 0) {
      const exceed = -left;
      newRx = newRx - exceed;
      if (newRx < 0) newRx = 0;
    }
    const right = x + newRx;
    if (right > w) {
      const exceed = right - w;
      newRx = newRx - exceed;
      if (newRx < 0) newRx = 0;
    }
    const top = y - newRy;
    if (top < 0) {
      const exceed = -top;
      newRy = newRy - exceed;
      if (newRy < 0) newRy = 0;
    }
    const bottom = y + newRy;
    if (bottom > h) {
      const exceed = bottom - h;
      newRy = newRy - exceed;
      if (newRy < 0) newRy = 0;
    }

    if (newRx < 1 || newRy < 1) {
      return null;
    }

    return {
      ...ellipse,
      radiusX: newRx,
      radiusY: newRy,
    };
  }

  function isPartiallyOutside(ann, w, h) {
    const box = shapeBoundingBox(ann);
    if (!box) return false;
    const { x1, y1, x2, y2 } = box;
    if (
      x2 < 0 ||
      x1 > w ||
      y2 < 0 ||
      y1 > h ||
      x1 < 0 ||
      x2 > w ||
      y1 < 0 ||
      y2 > h
    ) {
      return true;
    }
    return false;
  }

  function clipAnnotationToBoundary(ann, w, h) {
    if (!isPartiallyOutside(ann, w, h)) {
      return ann;
    }

    if (ann.type === 'bbox') {
      const clamped = clampBoundingBox(ann, w, h);
      return clamped;
    }

    if (ann.type === 'polygon') {
      const clipped = clipPolygonToRect(ann.points, w, h);
      if (clipped.length < 3) return null;
      return { ...ann, points: clipped };
    }

    if (ann.type === 'polyline') {
      const clippedLine = clipPolylineToRect(ann.points, w, h);
      if (clippedLine.length < 2) return null;
      return { ...ann, points: clippedLine };
    }

    if (ann.type === 'points') {
      const newPts = ann.points.map((p) => clampPointToRect(p, w, h));
      return { ...ann, points: newPts };
    }

    if (ann.type === 'point') {
      const clamped = clampPointToRect({ x: ann.x, y: ann.y }, w, h);
      return { ...ann, x: clamped.x, y: clamped.y };
    }

    if (ann.type === 'ellipse') {
      const clamped = clampEllipse(ann, w, h);
      return clamped;
    }

    return null;
  }

  // ----------- Creating BBox -----------
  function startBox(pos) {
    setNewBox({ x: pos.x, y: pos.y, width: 0, height: 0 });
  }
  function updateBox(pos) {
    if (!newBox) return;
    setNewBox({
      ...newBox,
      width: pos.x - newBox.x,
      height: pos.y - newBox.y,
    });
  }
  function finalizeBox() {
    if (!newBox) return;
    const newAnn = {
      type: 'bbox',
      ...newBox,
      label: activeLabel,
      color: activeLabelColor,
    };

    if (konvaImg) {
      const clipped = clipAnnotationToBoundary(
        newAnn,
        konvaImg.width,
        konvaImg.height
      );
      if (clipped) {
        onAnnotationsChange([...annotations, clipped]);
      }
    } else {
      onAnnotationsChange([...annotations, newAnn]);
    }
    setNewBox(null);
    onFinishShape && onFinishShape();
  }

  // ----------- Creating Polygon -----------
  function addPolygonPoint(pos) {
    setTempPoints((prev) => [...prev, pos]);
    setDrawingPolygon(true);
  }
  function finalizePolygon() {
    if (tempPoints.length >= 3) {
      const newAnn = {
        type: 'polygon',
        points: tempPoints,
        label: activeLabel,
        color: activeLabelColor,
      };
      if (konvaImg) {
        const clipped = clipAnnotationToBoundary(
          newAnn,
          konvaImg.width,
          konvaImg.height
        );
        if (clipped) {
          onAnnotationsChange([...annotations, clipped]);
        }
      } else {
        onAnnotationsChange([...annotations, newAnn]);
      }
    }
    setTempPoints([]);
    setDrawingPolygon(false);
    onFinishShape && onFinishShape();
  }

  // ----------- Creating Polyline -----------
  function addPolylinePoint(pos) {
    setTempPolyline((prev) => [...prev, pos]);
    setDrawingPolyline(true);
  }
  function finalizePolyline() {
    if (tempPolyline.length >= 2) {
      const newAnn = {
        type: 'polyline',
        points: tempPolyline,
        label: activeLabel,
        color: activeLabelColor,
      };
      if (konvaImg) {
        const clipped = clipAnnotationToBoundary(
          newAnn,
          konvaImg.width,
          konvaImg.height
        );
        if (clipped) {
          onAnnotationsChange([...annotations, clipped]);
        }
      } else {
        onAnnotationsChange([...annotations, newAnn]);
      }
    }
    setTempPolyline([]);
    setDrawingPolyline(false);
    onFinishShape && onFinishShape();
  }

  // ----------- Creating Points -----------
  function addPointToPoints(pos) {
    setTempPointPoints((prev) => [...prev, pos]);
    setDrawingPoint(true);
  }
  function finalizePoint() {
    if (tempPointPoints.length > 0) {
      const newAnn = {
        type: 'points',
        points: tempPointPoints,
        label: activeLabel,
        color: activeLabelColor,
      };
      if (konvaImg) {
        const clipped = clipAnnotationToBoundary(
          newAnn,
          konvaImg.width,
          konvaImg.height
        );
        if (clipped) {
          onAnnotationsChange([...annotations, clipped]);
        }
      } else {
        onAnnotationsChange([...annotations, newAnn]);
      }
    }
    setTempPointPoints([]);
    setDrawingPoint(false);
    onFinishShape && onFinishShape();
  }

  // ----------- Creating Ellipse -----------
  function startEllipse(pos) {
    setNewEllipse({
      type: 'ellipse',
      x: pos.x,
      y: pos.y,
      radiusX: 0,
      radiusY: 0,
      rotation: 0,
      label: activeLabel,
      color: activeLabelColor,
    });
  }
  function updateEllipse(pos) {
    if (!newEllipse) return;
    const rx = Math.abs(pos.x - newEllipse.x);
    const ry = Math.abs(pos.y - newEllipse.y);
    setNewEllipse({
      ...newEllipse,
      radiusX: rx,
      radiusY: ry,
    });
  }
  function finalizeEllipse() {
    if (!newEllipse) return;
    if (konvaImg) {
      const clipped = clipAnnotationToBoundary(
        newEllipse,
        konvaImg.width,
        konvaImg.height
      );
      if (clipped) {
        onAnnotationsChange([...annotations, clipped]);
      }
    } else {
      onAnnotationsChange([...annotations, { ...newEllipse }]);
    }
    setNewEllipse(null);
    onFinishShape && onFinishShape();
  }

  // ----------- Creating Instance Segmentation Polygon -----------
  function addInstancePolygonPoint(pos) {
    setTempInstancePoints((prev) => [...prev, pos]);
    setDrawingInstancePolygon(true);
  }
  function finalizeInstancePolygon() {
    if (tempInstancePoints.length >= 3) {
      let newAnn = {
        type: 'polygon',
        points: tempInstancePoints,
        label: activeLabel,
      };

      // instance ID and color variation
      const labelKey = activeLabel || 'unknown';
      const currentCount = instanceCounters[labelKey] || 0;
      const newCount = currentCount + 1;
      const instanceId = labelKey + '-' + newCount;

      const offset = -(newCount - 1) * 50;
      const instanceColor = shadeColor(activeLabelColor, offset);

      newAnn.instanceId = instanceId;
      newAnn.color = instanceColor;

      setInstanceCounters({
        ...instanceCounters,
        [labelKey]: newCount,
      });

      if (konvaImg) {
        const clipped = clipAnnotationToBoundary(
          newAnn,
          konvaImg.width,
          konvaImg.height
        );
        if (clipped) {
          onAnnotationsChange([...annotations, clipped]);
        }
      } else {
        onAnnotationsChange([...annotations, newAnn]);
      }
    }
    setTempInstancePoints([]);
    setDrawingInstancePolygon(false);
    onFinishShape && onFinishShape();
  }

  // ----------- Creating Semantic Segmentation Polygon -----------
  function addSemanticPolygonPoint(pos) {
    setTempSemanticPoints((prev) => [...prev, pos]);
    setDrawingSemanticPolygon(true);
  }
  function finalizeSemanticPolygon() {
    if (tempSemanticPoints.length >= 3) {
      const newAnn = {
        type: 'polygon',
        points: tempSemanticPoints,
        label: activeLabel,
        color: activeLabelColor,
      };
      if (konvaImg) {
        const clipped = clipAnnotationToBoundary(
          newAnn,
          konvaImg.width,
          konvaImg.height
        );
        if (clipped) {
          onAnnotationsChange([...annotations, clipped]);
        }
      } else {
        onAnnotationsChange([...annotations, newAnn]);
      }
    }
    setTempSemanticPoints([]);
    setDrawingSemanticPolygon(false);
    onFinishShape && onFinishShape();
  }

  // ----------- Cancel shape on ESC -----------
  useEffect(() => {
    const onCancelAnnotation = () => {
      setNewBox(null);
      setTempPoints([]);
      setDrawingPolygon(false);
      setTempPolyline([]);
      setDrawingPolyline(false);
      setNewEllipse(null);
      setTempPointPoints([]);
      setDrawingPoint(false);
      setTempInstancePoints([]);
      setDrawingInstancePolygon(false);
      setTempSemanticPoints([]);
      setDrawingSemanticPolygon(false);
    };
    window.addEventListener('cancel-annotation', onCancelAnnotation);
    return () =>
      window.removeEventListener('cancel-annotation', onCancelAnnotation);
  }, []);

  // ----------- Wheel Zoom -----------
  function handleWheel(evt) {
    evt.evt.preventDefault();
    onWheelZoom(evt.evt.deltaY);
  }

  // ----------- Right-click remove last *drawing* point -----------
  function handleContextMenu(evt) {
    evt.evt.preventDefault();
    // polygon
    if (selectedTool === 'polygon' && drawingPolygon && tempPoints.length > 0) {
      setTempPoints((prev) => prev.slice(0, -1));
    }
    // polyline
    else if (
      selectedTool === 'polyline' &&
      drawingPolyline &&
      tempPolyline.length > 0
    ) {
      setTempPolyline((prev) => prev.slice(0, -1));
    }
    // point
    else if (
      selectedTool === 'point' &&
      drawingPoint &&
      tempPointPoints.length > 0
    ) {
      setTempPointPoints((prev) => prev.slice(0, -1));
    }
    // instance
    else if (
      selectedTool === 'segmentation' &&
      segmentationType === 'instance' &&
      drawingInstancePolygon &&
      tempInstancePoints.length > 0
    ) {
      setTempInstancePoints((prev) => prev.slice(0, -1));
    }
    // semantic
    else if (
      selectedTool === 'segmentation' &&
      segmentationType === 'semantic' &&
      drawingSemanticPolygon &&
      tempSemanticPoints.length > 0
    ) {
      setTempSemanticPoints((prev) => prev.slice(0, -1));
    }
  }

  // ----------- Mouse events for shape creation -----------
  function handleMouseDown(evt) {
    if (selectedTool === 'move') {
      return;
    }
    const pos = getGroupPos(evt);
    if (!pos) return;

    const now = Date.now();
    const delta = now - lastClickTimeRef.current;
    const usesDoubleClick =
      selectedTool === 'polygon' ||
      selectedTool === 'polyline' ||
      selectedTool === 'point' ||
      (selectedTool === 'segmentation' && segmentationType === 'instance') ||
      (selectedTool === 'segmentation' && segmentationType === 'semantic');

    if (usesDoubleClick && delta < doubleClickThreshold) {
      return; // double-click => handled in handleDblClick
    }
    lastClickTimeRef.current = now;

    if (selectedTool === 'bbox') {
      startBox(pos);
    } else if (selectedTool === 'polygon') {
      addPolygonPoint(pos);
    } else if (selectedTool === 'polyline') {
      addPolylinePoint(pos);
    } else if (selectedTool === 'point') {
      addPointToPoints(pos);
    } else if (selectedTool === 'ellipse') {
      startEllipse(pos);
    } else if (
      selectedTool === 'segmentation' &&
      segmentationType === 'instance'
    ) {
      addInstancePolygonPoint(pos);
    } else if (
      selectedTool === 'segmentation' &&
      segmentationType === 'semantic'
    ) {
      addSemanticPolygonPoint(pos);
    }
  }

  function handleMouseMove(evt) {
    if (selectedTool === 'bbox' && newBox) {
      const pos = getGroupPos(evt);
      if (pos) updateBox(pos);
    } else if (selectedTool === 'ellipse' && newEllipse) {
      const pos = getGroupPos(evt);
      if (pos) updateEllipse(pos);
    }
  }

  function handleMouseUp() {
    if (selectedTool === 'bbox' && newBox) {
      finalizeBox();
    } else if (selectedTool === 'ellipse' && newEllipse) {
      finalizeEllipse();
    }
  }

  function handleDblClick() {
    if (selectedTool === 'polygon' && drawingPolygon) {
      finalizePolygon();
    } else if (selectedTool === 'polyline' && drawingPolyline) {
      finalizePolyline();
    } else if (selectedTool === 'point' && drawingPoint) {
      finalizePoint();
    } else if (
      selectedTool === 'segmentation' &&
      segmentationType === 'instance' &&
      drawingInstancePolygon
    ) {
      finalizeInstancePolygon();
    } else if (
      selectedTool === 'segmentation' &&
      segmentationType === 'semantic' &&
      drawingSemanticPolygon
    ) {
      finalizeSemanticPolygon();
    }
  }

  // ----------- Copy/Paste Keyboard Listener -----------
  useEffect(() => {
    const handleKeyDown = (e) => {
      // Copy
      if (e.ctrlKey && (e.key === 'c' || e.key === 'C')) {
        if (selectedAnnotationIndex !== null) {
          e.preventDefault();
          setCopiedAnnotation(annotations[selectedAnnotationIndex]);
        }
      }
      // Paste
      if (e.ctrlKey && (e.key === 'v' || e.key === 'V')) {
        if (copiedAnnotation) {
          e.preventDefault();
          const newAnn = JSON.parse(JSON.stringify(copiedAnnotation));
          // Shift it slightly
          if (newAnn.x !== undefined && newAnn.y !== undefined) {
            newAnn.x += 10;
            newAnn.y += 10;
          } else if (newAnn.points) {
            newAnn.points = newAnn.points.map((pt) => ({
              x: pt.x + 10,
              y: pt.y + 10,
            }));
          }
          onAnnotationsChange([...annotations, newAnn]);
        }
      }

      // Remove last "drawing" point if user is in the middle of creating polygon, etc.
      if (e.key === 'Backspace' || e.key === 'Delete') {
        // Polygon
        if (selectedTool === 'polygon' && drawingPolygon && tempPoints.length > 0) {
          e.preventDefault();
          setTempPoints((prev) => prev.slice(0, -1));
        }
        // Polyline
        else if (
          selectedTool === 'polyline' &&
          drawingPolyline &&
          tempPolyline.length > 0
        ) {
          e.preventDefault();
          setTempPolyline((prev) => prev.slice(0, -1));
        }
        // Point
        else if (
          selectedTool === 'point' &&
          drawingPoint &&
          tempPointPoints.length > 0
        ) {
          e.preventDefault();
          setTempPointPoints((prev) => prev.slice(0, -1));
        }
        // Instance
        else if (
          selectedTool === 'segmentation' &&
          segmentationType === 'instance' &&
          drawingInstancePolygon &&
          tempInstancePoints.length > 0
        ) {
          e.preventDefault();
          setTempInstancePoints((prev) => prev.slice(0, -1));
        }
        // Semantic
        else if (
          selectedTool === 'segmentation' &&
          segmentationType === 'semantic' &&
          drawingSemanticPolygon &&
          tempSemanticPoints.length > 0
        ) {
          e.preventDefault();
          setTempSemanticPoints((prev) => prev.slice(0, -1));
        }
      }
    };

    window.addEventListener('keydown', handleKeyDown);
    return () => window.removeEventListener('keydown', handleKeyDown);
  }, [
    annotations,
    onAnnotationsChange,
    selectedAnnotationIndex,
    copiedAnnotation,
    selectedTool,
    drawingPolygon,
    drawingPolyline,
    drawingPoint,
    drawingInstancePolygon,
    tempPoints,
    tempPolyline,
    tempPointPoints,
    tempInstancePoints,
    drawingSemanticPolygon,
    tempSemanticPoints,
    segmentationType
  ]);

  // ----------- Draggable logic for entire shapes -----------
  const handleBBoxDragEnd = (index, e) => {
    const { x, y } = e.target.position();
    const updated = [...annotations];
    updated[index] = { ...updated[index], x, y };

    if (konvaImg) {
      const clipped = clipAnnotationToBoundary(
        updated[index],
        konvaImg.width,
        konvaImg.height
      );
      if (!clipped) {
        updated.splice(index, 1);
      } else {
        updated[index] = clipped;
      }
    }
    onAnnotationsChange(updated);
  };

  const handleEllipseDragEnd = (index, e) => {
    const { x, y } = e.target.position();
    const updated = [...annotations];
    updated[index] = { ...updated[index], x, y };

    if (konvaImg && isPartiallyOutside(updated[index], konvaImg.width, konvaImg.height)) {
      const clipped = clipAnnotationToBoundary(
        updated[index],
        konvaImg.width,
        konvaImg.height
      );
      if (!clipped) {
        updated.splice(index, 1);
      } else {
        updated[index] = clipped;
      }
    }
    onAnnotationsChange(updated);
  };

  const handlePointDragEnd = (index, e) => {
    const { x, y } = e.target.position();
    const updated = [...annotations];
    updated[index] = { ...updated[index], x, y };

    if (konvaImg) {
      const clipped = clipAnnotationToBoundary(
        updated[index],
        konvaImg.width,
        konvaImg.height
      );
      if (!clipped) {
        updated.splice(index, 1);
      } else {
        updated[index] = clipped;
      }
    }
    onAnnotationsChange(updated);
  };

  const handlePolylineDragEnd = (index, e) => {
    const { x, y } = e.target.position();
    const ann = annotations[index];
    const newPoints = ann.points.map((pt) => ({
      x: pt.x + x,
      y: pt.y + y,
    }));
    const updated = [...annotations];
    updated[index] = { ...ann, points: newPoints };
    e.target.position({ x: 0, y: 0 });

    if (konvaImg) {
      const clipped = clipAnnotationToBoundary(
        updated[index],
        konvaImg.width,
        konvaImg.height
      );
      if (!clipped) {
        updated.splice(index, 1);
      } else {
        updated[index] = clipped;
      }
    }
    onAnnotationsChange(updated);
  };

  const handlePolygonDragEnd = (index, e) => {
    const { x, y } = e.target.position();
    const ann = annotations[index];
    const newPoints = ann.points.map((pt) => ({
      x: pt.x + x,
      y: pt.y + y,
    }));
    const updated = [...annotations];
    updated[index] = { ...ann, points: newPoints };
    e.target.position({ x: 0, y: 0 });

    if (konvaImg) {
      const clipped = clipAnnotationToBoundary(
        updated[index],
        konvaImg.width,
        konvaImg.height
      );
      if (!clipped) {
        updated.splice(index, 1);
      } else {
        updated[index] = clipped;
      }
    }
    onAnnotationsChange(updated);
  };

  // ----------- Remove an individual vertex -----------
  function handleRemoveVertex(annIndex, vertexIndex) {
    const updated = [...annotations];
    const ann = { ...updated[annIndex] };
    const shapePoints = [...ann.points];
    shapePoints.splice(vertexIndex, 1);

    if (ann.type === 'polygon' && shapePoints.length < 3) {
      updated.splice(annIndex, 1);
    } else if (ann.type === 'polyline' && shapePoints.length < 2) {
      updated.splice(annIndex, 1);
    } else if (ann.type === 'points' && shapePoints.length < 1) {
      updated.splice(annIndex, 1);
    } else {
      ann.points = shapePoints;
      updated[annIndex] = ann;
    }

    onAnnotationsChange(updated);
  }

  // ----------- Insert a new vertex between current vertex and next -----------
  function handleInsertVertex(annIndex, vertexIndex) {
    const updated = [...annotations];
    const ann = { ...updated[annIndex] };

    if (ann.type !== 'polygon' && ann.type !== 'polyline') return;

    const shapePoints = [...ann.points];
    const length = shapePoints.length;
    if (length < 2) return;

    let nextIndex;
    if (ann.type === 'polygon') {
      nextIndex = (vertexIndex + 1) % length;
    } else {
      if (vertexIndex === length - 1) {
        return;
      }
      nextIndex = vertexIndex + 1;
    }

    const currentPt = shapePoints[vertexIndex];
    const nextPt = shapePoints[nextIndex];

    const midX = (currentPt.x + nextPt.x) / 2;
    const midY = (currentPt.y + nextPt.y) / 2;

    shapePoints.splice(vertexIndex + 1, 0, { x: midX, y: midY });

    ann.points = shapePoints;
    updated[annIndex] = ann;
    onAnnotationsChange(updated);
  }

  // ----------- Draggable logic for each vertex -----------
  const handleVertexDragEnd = (annIndex, vertexIndex, e) => {
    e.cancelBubble = true;
    const { x, y } = e.target.position();
    const updated = [...annotations];
    const shapePoints = [...updated[annIndex].points];
    shapePoints[vertexIndex] = { x, y };
    updated[annIndex] = { ...updated[annIndex], points: shapePoints };

    if (konvaImg) {
      if (updated[annIndex].type === 'polygon') {
        const clipped = clipAnnotationToBoundary(
          updated[annIndex],
          konvaImg.width,
          konvaImg.height
        );
        if (!clipped) {
          updated.splice(annIndex, 1);
        } else {
          updated[annIndex] = clipped;
        }
      } else if (updated[annIndex].type === 'polyline') {
        const clipped = clipAnnotationToBoundary(
          updated[annIndex],
          konvaImg.width,
          konvaImg.height
        );
        if (!clipped) {
          updated.splice(annIndex, 1);
        } else {
          updated[annIndex] = clipped;
        }
      } else {
        // e.g. points
        const clipped = clipAnnotationToBoundary(
          updated[annIndex],
          konvaImg.width,
          konvaImg.height
        );
        if (!clipped) {
          updated.splice(annIndex, 1);
        } else {
          updated[annIndex] = clipped;
        }
      }
    }
    onAnnotationsChange(updated);
  };

  // ----------- Transformer logic (for bbox & ellipse) -----------
  useEffect(() => {
    const tr = transformerRef.current;
    if (!tr) return;

    if (selectedAnnotationIndex == null) {
      tr.nodes([]);
      return;
    }
    const node = shapeRefs.current[selectedAnnotationIndex];
    if (node) {
      tr.nodes([node]);
      tr.getLayer().batchDraw();
    } else {
      tr.nodes([]);
    }
  }, [selectedAnnotationIndex, annotations]);

  const handleTransformEnd = () => {
    if (selectedAnnotationIndex == null) return;
    const shapeNode = shapeRefs.current[selectedAnnotationIndex];
    if (!shapeNode) return;

    const ann = annotations[selectedAnnotationIndex];
    const scaleX = shapeNode.scaleX();
    const scaleY = shapeNode.scaleY();
    const offsetX = shapeNode.x();
    const offsetY = shapeNode.y();

    let updatedAnn = { ...ann };

    switch (ann.type) {
      case 'bbox': {
        const newWidth = shapeNode.width() * scaleX;
        const newHeight = shapeNode.height() * scaleY;
        updatedAnn.x = offsetX;
        updatedAnn.y = offsetY;
        updatedAnn.width = newWidth;
        updatedAnn.height = newHeight;
        break;
      }
      case 'ellipse': {
        const newRadiusX = (shapeNode.width() / 2) * scaleX;
        const newRadiusY = (shapeNode.height() / 2) * scaleY;
        updatedAnn.x = offsetX;
        updatedAnn.y = offsetY;
        updatedAnn.radiusX = newRadiusX;
        updatedAnn.radiusY = newRadiusY;
        break;
      }
      default:
        break;
    }

    shapeNode.scaleX(1);
    shapeNode.scaleY(1);
    shapeNode.x(0);
    shapeNode.y(0);

    const updatedAll = [...annotations];
    updatedAll[selectedAnnotationIndex] = updatedAnn;

    if (konvaImg) {
      const clipped = clipAnnotationToBoundary(
        updatedAnn,
        konvaImg.width,
        konvaImg.height
      );
      if (!clipped) {
        updatedAll.splice(selectedAnnotationIndex, 1);
      } else {
        updatedAll[selectedAnnotationIndex] = clipped;
      }
    }

    onAnnotationsChange(updatedAll);
  };

  // -----------------------------------------------------------------------------------
  //                             FILL BACKGROUND FEATURE
  // -----------------------------------------------------------------------------------
  // 1. We'll expose a method via ref: fillBackground()
  // 2. This method:
  //    - Checks if we have an image loaded.
  //    - Computes a polygon (or set of polygons) = entire image minus any existing shapes.
  //    - Asks user for a background label name (default "background").
  //    - Picks a color (default black) that doesn't clash with existing label colors.
  //    - Adds the resulting polygon(s) to annotations with that label + color.
  //
  // Note: We'll store multiple polygons if the difference results in multiple disjoint areas.
  // Each polygon is an annotation of type 'polygon'. The user sees "holes" in the final result
  // by virtue of each region being separate polygons. This is simpler with the existing logic.

  useImperativeHandle(ref, () => ({
    fillBackground: () => fillBackgroundHandler(),
  }));

  function fillBackgroundHandler() {
    if (!konvaImg) {
      alert('No image loaded. Cannot fill background.');
      return;
    }
    // Only relevant for semantic or panoptic
    if (!(segmentationType === 'semantic' || segmentationType === 'panoptic')) {
      alert('Fill Background is only for semantic or panoptic segmentation.');
      return;
    }

    const w = konvaImg.width;
    const h = konvaImg.height;

    // Ask user for background label name
    let bgLabel = prompt('Enter label for background:', 'background');
    if (!bgLabel) {
      bgLabel = 'background';
    }

    // Determine a color for the background annotation
    let desiredColor = '#000000'; // default black
    // If black is already used, shift it slightly (e.g. #010101, #020202, etc.)
    const usedColors = new Set(labelClasses.map((lc) => lc.color.toLowerCase()));
    let attempts = 1;
    while (usedColors.has(desiredColor.toLowerCase())) {
      const hexVal = attempts.toString(16).padStart(2, '0');
      desiredColor = `#${hexVal}${hexVal}${hexVal}`;
      attempts++;
      if (attempts > 255) break; // fallback
    }

    // The polygon that covers the entire image
    const baseRectPolygon = [
      { x: 0, y: 0 },
      { x: w, y: 0 },
      { x: w, y: h },
      { x: 0, y: h },
    ];

    // Convert each annotation to a polygon (approx).
    // Then subtract it from baseRectPolygon repeatedly.
    // The result is the set of polygons that fill all non-annotated space.

    // We'll store the result as an array of polygons (disjoint or with holes).
    let currentPolygons = [baseRectPolygon];

    // Helper: approximate an ellipse with N segments
    function ellipseToPolygon(ellipse, segments = 32) {
      const result = [];
      for (let i = 0; i < segments; i++) {
        const theta = (2 * Math.PI * i) / segments;
        result.push({
          x: ellipse.x + ellipse.radiusX * Math.cos(theta),
          y: ellipse.y + ellipse.radiusY * Math.sin(theta),
        });
      }
      return result;
    }

    // Helper: approximate a polyline, bounding box, or points as polygon with minimal area
    // (we can't easily do a "hole" from a line, but let's treat polylines and points as tiny polygons)
    // However, if we want truly to exclude them, let's give them at least some area or treat polylines as polygons:
    // For simplicity, bounding boxes => 4-corner polygon
    // polylines => bounding box
    // points => a small 4x4 box around the point
    function annotationToPolygon(ann) {
      switch (ann.type) {
        case 'bbox': {
          return [
            { x: ann.x, y: ann.y },
            { x: ann.x + ann.width, y: ann.y },
            { x: ann.x + ann.width, y: ann.y + ann.height },
            { x: ann.x, y: ann.y + ann.height },
          ];
        }
        case 'ellipse': {
          return ellipseToPolygon(ann, 32);
        }
        case 'polygon': {
          return ann.points.map((p) => ({ x: p.x, y: p.y }));
        }
        case 'polyline': {
          // approximate as bounding box:
          let minX = Infinity, maxX = -Infinity, minY = Infinity, maxY = -Infinity;
          ann.points.forEach((p) => {
            if (p.x < minX) minX = p.x;
            if (p.x > maxX) maxX = p.x;
            if (p.y < minY) minY = p.y;
            if (p.y > maxY) maxY = p.y;
          });
          return [
            { x: minX, y: minY },
            { x: maxX, y: minY },
            { x: maxX, y: maxY },
            { x: minX, y: maxY },
          ];
        }
        case 'point': {
          // small 4x4 box around the point
          const r = 2;
          return [
            { x: ann.x - r, y: ann.y - r },
            { x: ann.x + r, y: ann.y - r },
            { x: ann.x + r, y: ann.y + r },
            { x: ann.x - r, y: ann.y + r },
          ];
        }
        case 'points': {
          // bounding box around all points
          let minX = Infinity, maxX = -Infinity, minY = Infinity, maxY = -Infinity;
          ann.points.forEach((p) => {
            if (p.x < minX) minX = p.x;
            if (p.x > maxX) maxX = p.x;
            if (p.y < minY) minY = p.y;
            if (p.y > maxY) maxY = p.y;
          });
          return [
            { x: minX, y: minY },
            { x: maxX, y: minY },
            { x: maxX, y: maxY },
            { x: minX, y: maxY },
          ];
        }
        default:
          return null;
      }
    }

    // We'll implement a simple polygon difference routine that does:
    //   result = differenceMany(currentPolygons, shapePolygon)
    // repeatedly. For polygon difference, we can do Sutherland–Hodgman for clipping, but
    // we want "subtract shapePolygon from each polygon in currentPolygons."
    // This can produce multiple new polygons if shapePolygon splits an existing polygon.
    // The code below is a simplified approach and might not handle all corner cases,
    // but demonstrates the logic.  

    function polygonDifference(subjectPoly, clipPoly) {
      // We'll do a naive approach:
      // subjectPoly - clipPoly = subjectPoly ∩ (inverse(clipPoly))
      // But we'll hack it with repeated clipping to edges of clipPoly, in "outside" mode.
      // We'll treat clipPoly edges as "inside" is outside the polygon. Then keep what's outside.
      // Implementation adapted from Sutherland–Hodgman but "outside" version.
      //
      // If the final result is empty or partially splitted, we'll return array of polygons if splitted.
      // For simplicity, we keep it to a single pass that might produce holes as separate polygons.
      // Full multi-polygon support is complicated. We'll keep it minimal here.

      // We'll do a polygon-polygon clip approach that only returns one polygon. In real usage,
      // you might want a robust library to handle multiple disjoint pieces. We'll do a quick
      // approach that returns a single array of points per "piece" we find, so we can track them.

      // Step 1: Triangulate clipPoly edges for "cutting" ... Actually let's do a simpler approach:
      // We'll do multiple edge clipping in the "outside" region sense.

      let outputListArr = [subjectPoly]; // start with single polygon
      const len = clipPoly.length;

      // Helper: return if a point is inside the polygon using even-odd or winding. We want "outside"
      // We'll do a simple winding or ray-casting:
      function isInsidePolygon(pt, poly) {
        let inside = false;
        for (let i = 0, j = poly.length - 1; i < poly.length; j = i++) {
          const xi = poly[i].x, yi = poly[i].y;
          const xj = poly[j].x, yj = poly[j].y;
          const intersect = ((yi > pt.y) !== (yj > pt.y)) &&
            (pt.x < (xj - xi) * (pt.y - yi) / (yj - yi) + xi);
          if (intersect) inside = !inside;
        }
        return inside;
      }

      // For each piece in outputListArr, we check each edge of clipPoly, keep only points outside that edge.
      for (let c = 0; c < len; c++) {
        const nextC = (c + 1) % len;
        const clipStart = clipPoly[c];
        const clipEnd = clipPoly[nextC];

        const inputPolygons = outputListArr;
        outputListArr = [];

        for (const inPoly of inputPolygons) {
          if (inPoly.length < 3) continue;
          const outPoly = [];
          for (let i = 0; i < inPoly.length; i++) {
            const current = inPoly[i];
            const prev = inPoly[(i + inPoly.length - 1) % inPoly.length];

            const curSide = isOutsideEdge(current, clipStart, clipEnd);
            const prevSide = isOutsideEdge(prev, clipStart, clipEnd);

            if (prevSide && curSide) {
              // both outside => keep current
              outPoly.push(current);
            } else if (prevSide && !curSide) {
              // crossing from outside to inside => intersection
              const inter = computeIntersect(prev, current, clipStart, clipEnd);
              if (inter) outPoly.push(inter);
            } else if (!prevSide && curSide) {
              // crossing from inside to outside => intersection + current
              const inter = computeIntersect(prev, current, clipStart, clipEnd);
              if (inter) outPoly.push(inter);
              outPoly.push(current);
            }
          }
          if (outPoly.length >= 3) {
            outputListArr.push(outPoly);
          }
        }
      }

      // Now we also must remove sub-polygons that lie completely inside clipPoly, since we want outside.
      // We'll filter them out. If the midpoint of a polygon is inside clipPoly, we drop it.
      let finalPolys = [];
      for (const poly of outputListArr) {
        const mp = getPolygonMidpoint(poly);
        if (!isInsidePolygon(mp, clipPoly)) {
          finalPolys.push(poly);
        }
      }

      return finalPolys;

      function getPolygonMidpoint(poly) {
        let xSum = 0, ySum = 0;
        poly.forEach((p) => {
          xSum += p.x;
          ySum += p.y;
        });
        return { x: xSum / poly.length, y: ySum / poly.length };
      }

      function isOutsideEdge(pt, A, B) {
        // We'll treat "left side" as inside or outside. We'll do an orientation check. 
        // Actually, we want points to be on the "right side" => outside. We'll define an orientation test:
        return orientation(A, B, pt) < 0;
      }

      function orientation(a, b, c) {
        // cross product (b-a)x(c-a)
        return (b.x - a.x) * (c.y - a.y) - (b.y - a.y) * (c.x - a.x);
      }

      function computeIntersect(a, b, c, d) {
        // line AB and line CD intersection
        const denom = (d.y - c.y) * (b.x - a.x) - (d.x - c.x) * (b.y - a.y);
        if (Math.abs(denom) < 1e-9) return null; // parallel

        const ua = ((d.x - c.x) * (a.y - c.y) - (d.y - c.y) * (a.x - c.x)) / denom;
        const x = a.x + ua * (b.x - a.x);
        const y = a.y + ua * (b.y - a.y);
        return { x, y };
      }
    }

    function differenceMany(subjectPolys, clipPoly) {
      let result = [];
      for (const sub of subjectPolys) {
        const diffs = polygonDifference(sub, clipPoly);
        if (diffs.length > 0) {
          result.push(...diffs);
        }
      }
      return result;
    }

    // Perform repeated difference for each annotation
    for (let ann of annotations) {
      const poly = annotationToPolygon(ann);
      if (!poly) continue;
      currentPolygons = differenceMany(currentPolygons, poly);
      if (currentPolygons.length === 0) break;
    }

    // Now we have an array of polygons (each polygon is array of {x,y}).
    // We'll add each as an annotation with type "polygon", label=bgLabel, color=desiredColor.
    if (currentPolygons.length === 0) {
      alert('No background area remains unannotated!');
      return;
    }

    const newBackgroundAnnotations = currentPolygons.map((poly) => ({
      type: 'polygon',
      points: poly,
      label: bgLabel,
      color: desiredColor,
    }));

    // Add them to the annotation list
    onAnnotationsChange([...annotations, ...newBackgroundAnnotations]);
    alert(`Background polygons added with label "${bgLabel}"!`);
  }
  // -----------------------------------------------------------------------------------

  return (
    <div className="canvas-container" ref={containerRef}>
      <Stage
        ref={stageRef}
        width={dims.width}
        height={dims.height}
        scaleX={scale}
        scaleY={scale}
        style={{ background: '#dfe6e9' }}
        onWheel={handleWheel}
        onMouseDown={handleMouseDown}
        onMouseMove={handleMouseMove}
        onMouseUp={handleMouseUp}
        onDblClick={handleDblClick}
        onContextMenu={handleContextMenu}
      >
        <Layer>
          <Group
            id="anno-group"
            draggable={selectedTool === 'move'}
            x={imagePos.x}
            y={imagePos.y}
            onDragEnd={(e) => {
              setImagePos({ x: e.target.x(), y: e.target.y() });
            }}
          >
            {/* Background image */}
            {konvaImg && (
              <KonvaImage
                image={konvaImg}
                width={konvaImg.width}
                height={konvaImg.height}
              />
            )}

            {/* Render existing annotations */}
            {annotations.map((ann, i) => {
              const annColor = ann.color || activeLabelColor || '#ff0000';
              const fillColor = annColor + '55';

              if (ann.type === 'bbox') {
                return (
                  <React.Fragment key={i}>
                    <Rect
                      ref={(node) => (shapeRefs.current[i] = node)}
                      x={ann.x}
                      y={ann.y}
                      width={ann.width}
                      height={ann.height}
                      fill={fillColor}
                      stroke={annColor}
                      strokeWidth={2 / scale}
                      draggable
                      onMouseDown={(e) => (e.cancelBubble = true)}
                      onDragStart={(e) => (e.cancelBubble = true)}
                      onDragMove={(e) => (e.cancelBubble = true)}
                      onDragEnd={(e) => {
                        e.cancelBubble = true;
                        handleBBoxDragEnd(i, e);
                      }}
                      onClick={(e) => {
                        if (selectedTool === 'move') {
                          e.cancelBubble = true;
                          setSelectedAnnotationIndex(i);
                        }
                      }}
                    />
                    {selectedAnnotationIndex === i && (
                      <>
                        <DeleteLabel
                          annotation={ann}
                          scale={scale}
                          shapeBoundingBox={shapeBoundingBox}
                          onDelete={() => onDeleteAnnotation(i)}
                          color={annColor}
                        />
                      </>
                    )}
                  </React.Fragment>
                );
              } else if (ann.type === 'ellipse') {
                return (
                  <React.Fragment key={i}>
                    <Ellipse
                      ref={(node) => (shapeRefs.current[i] = node)}
                      x={ann.x}
                      y={ann.y}
                      radiusX={ann.radiusX}
                      radiusY={ann.radiusY}
                      rotation={ann.rotation || 0}
                      fill={fillColor}
                      stroke={annColor}
                      strokeWidth={2 / scale}
                      draggable
                      onMouseDown={(e) => (e.cancelBubble = true)}
                      onDragStart={(e) => (e.cancelBubble = true)}
                      onDragMove={(e) => (e.cancelBubble = true)}
                      onDragEnd={(e) => {
                        e.cancelBubble = true;
                        handleEllipseDragEnd(i, e);
                      }}
                      onClick={(e) => {
                        if (selectedTool === 'move') {
                          e.cancelBubble = true;
                          setSelectedAnnotationIndex(i);
                        }
                      }}
                    />
                    {selectedAnnotationIndex === i && (
                      <>
                        <DeleteLabel
                          annotation={ann}
                          scale={scale}
                          shapeBoundingBox={shapeBoundingBox}
                          onDelete={() => onDeleteAnnotation(i)}
                          color={annColor}
                        />
                      </>
                    )}
                  </React.Fragment>
                );
              } else if (ann.type === 'point') {
                return (
                  <React.Fragment key={i}>
                    <Circle
                      x={ann.x}
                      y={ann.y}
                      radius={6 / scale}
                      fill={annColor}
                      draggable
                      onMouseDown={(e) => (e.cancelBubble = true)}
                      onDragEnd={(e) => {
                        e.cancelBubble = true;
                        handlePointDragEnd(i, e);
                      }}
                      onClick={(e) => {
                        if (selectedTool === 'move') {
                          e.cancelBubble = true;
                          setSelectedAnnotationIndex(i);
                        }
                      }}
                    />
                    {selectedAnnotationIndex === i && (
                      <>
                        <DeleteLabel
                          annotation={ann}
                          scale={scale}
                          shapeBoundingBox={shapeBoundingBox}
                          onDelete={() => onDeleteAnnotation(i)}
                          color={annColor}
                        />
                      </>
                    )}
                  </React.Fragment>
                );
              } else if (ann.type === 'polyline') {
                const pts = flattenPoints(ann.points);
                const firstPt = ann.points[0];
                const secondPt =
                  ann.points[1] || { x: firstPt.x + 10, y: firstPt.y };
                return (
                  <React.Fragment key={i}>
                    <Group
                      draggable
                      onMouseDown={(e) => (e.cancelBubble = true)}
                      onDragEnd={(e) => {
                        e.cancelBubble = true;
                        handlePolylineDragEnd(i, e);
                      }}
                      onClick={(e) => {
                        if (selectedTool === 'move') {
                          e.cancelBubble = true;
                          setSelectedAnnotationIndex(i);
                        }
                      }}
                    >
                      <Line
                        points={pts}
                        stroke={annColor}
                        strokeWidth={2 / scale}
                        closed={false}
                      />
                      {ann.points.map((pt, idx) => (
                        <Circle
                          key={idx}
                          x={pt.x}
                          y={pt.y}
                          radius={4 / scale}
                          fill="#fff"
                          stroke={annColor}
                          strokeWidth={1 / scale}
                          draggable
                          onMouseDown={(ev) => (ev.cancelBubble = true)}
                          onDragEnd={(ev) => handleVertexDragEnd(i, idx, ev)}
                          onContextMenu={(ev) => {
                            ev.evt.preventDefault();
                            ev.cancelBubble = true;
                            handleRemoveVertex(i, idx);
                          }}
                          onClick={(ev) => {
                            ev.cancelBubble = true;
                            handleInsertVertex(i, idx);
                          }}
                        />
                      ))}
                      <Arrow
                        points={[secondPt.x, secondPt.y, firstPt.x, firstPt.y]}
                        fill={annColor}
                        stroke={annColor}
                        strokeWidth={2 / scale}
                        pointerLength={10 / scale}
                        pointerWidth={8 / scale}
                      />
                    </Group>
                    {selectedAnnotationIndex === i && (
                      <>
                        <DeleteLabel
                          annotation={ann}
                          scale={scale}
                          shapeBoundingBox={shapeBoundingBox}
                          onDelete={() => onDeleteAnnotation(i)}
                          color={annColor}
                        />
                      </>
                    )}
                  </React.Fragment>
                );
              } else if (ann.type === 'polygon') {
                const pts = flattenPoints(ann.points);
                const firstPt = ann.points[0];
                const secondPt =
                  ann.points[1] || { x: firstPt.x + 10, y: firstPt.y };
                return (
                  <React.Fragment key={i}>
                    <Group
                      draggable
                      onMouseDown={(e) => (e.cancelBubble = true)}
                      onDragEnd={(e) => {
                        e.cancelBubble = true;
                        handlePolygonDragEnd(i, e);
                      }}
                      onClick={(e) => {
                        if (selectedTool === 'move') {
                          e.cancelBubble = true;
                          setSelectedAnnotationIndex(i);
                        }
                      }}
                    >
                      <Line
                        points={pts}
                        fill={fillColor}
                        stroke={annColor}
                        strokeWidth={2 / scale}
                        closed
                      />
                      {ann.points.map((pt, idx) => (
                        <Circle
                          key={idx}
                          x={pt.x}
                          y={pt.y}
                          radius={4 / scale}
                          fill="#fff"
                          stroke={annColor}
                          strokeWidth={1 / scale}
                          draggable
                          onMouseDown={(ev) => (ev.cancelBubble = true)}
                          onDragEnd={(ev) => handleVertexDragEnd(i, idx, ev)}
                          onContextMenu={(ev) => {
                            ev.evt.preventDefault();
                            ev.cancelBubble = true;
                            handleRemoveVertex(i, idx);
                          }}
                          onClick={(ev) => {
                            ev.cancelBubble = true;
                            handleInsertVertex(i, idx);
                          }}
                        />
                      ))}
                      <Arrow
                        points={[secondPt.x, secondPt.y, firstPt.x, firstPt.y]}
                        fill={annColor}
                        stroke={annColor}
                        strokeWidth={2 / scale}
                        pointerLength={10 / scale}
                        pointerWidth={8 / scale}
                      />
                    </Group>
                    {/* If it's an instance, we show instanceId */}
                    {ann.instanceId && (
                      <InstanceIdLabel
                        annotation={ann}
                        scale={scale}
                        shapeBoundingBox={shapeBoundingBox}
                        color={annColor}
                      />
                    )}
                    {selectedAnnotationIndex === i && (
                      <>
                        <DeleteLabel
                          annotation={ann}
                          scale={scale}
                          shapeBoundingBox={shapeBoundingBox}
                          onDelete={() => onDeleteAnnotation(i)}
                          color={annColor}
                        />
                      </>
                    )}
                  </React.Fragment>
                );
              } else if (ann.type === 'points') {
                return (
                  <React.Fragment key={i}>
                    <Group
                      draggable
                      onMouseDown={(e) => (e.cancelBubble = true)}
                      onDragEnd={(e) => {
                        e.cancelBubble = true;
                        handlePolylineDragEnd(i, e);
                      }}
                      onClick={(e) => {
                        if (selectedTool === 'move') {
                          e.cancelBubble = true;
                          setSelectedAnnotationIndex(i);
                        }
                      }}
                    >
                      {ann.points.map((pt, idx) => (
                        <Circle
                          key={idx}
                          x={pt.x}
                          y={pt.y}
                          radius={6 / scale}
                          fill={annColor}
                          draggable
                          onMouseDown={(ev) => (ev.cancelBubble = true)}
                          onDragEnd={(ev) => handleVertexDragEnd(i, idx, ev)}
                          onContextMenu={(ev) => {
                            ev.evt.preventDefault();
                            ev.cancelBubble = true;
                            handleRemoveVertex(i, idx);
                          }}
                        />
                      ))}
                    </Group>
                    {selectedAnnotationIndex === i && (
                      <>
                        <DeleteLabel
                          annotation={ann}
                          scale={scale}
                          shapeBoundingBox={shapeBoundingBox}
                          onDelete={() => onDeleteAnnotation(i)}
                          color={annColor}
                        />
                      </>
                    )}
                  </React.Fragment>
                );
              }
              return null;
            })}

            {/* In-progress BBox */}
            {newBox && selectedTool === 'bbox' && (
              <Rect
                x={newBox.x}
                y={newBox.y}
                width={newBox.width}
                height={newBox.height}
                fill={activeLabelColor + '55'}
                stroke={activeLabelColor}
                strokeWidth={2 / scale}
              />
            )}

            {/* In-progress Polygon */}
            {drawingPolygon && selectedTool === 'polygon' && (
              <>
                {tempPoints.length > 1 && (
                  <Line
                    points={flattenPoints([...tempPoints, tempPoints[0]])}
                    fill={activeLabelColor + '55'}
                    stroke={activeLabelColor}
                    strokeWidth={2 / scale}
                    closed
                  />
                )}
                {tempPoints.map((pt, idx) => (
                  <Circle
                    key={idx}
                    x={pt.x}
                    y={pt.y}
                    radius={4 / scale}
                    fill="#fff"
                    stroke={activeLabelColor}
                    strokeWidth={1 / scale}
                  />
                ))}
              </>
            )}

            {/* In-progress Polyline */}
            {drawingPolyline && selectedTool === 'polyline' && (
              <>
                {tempPolyline.length > 1 && (
                  <Line
                    points={flattenPoints(tempPolyline)}
                    stroke={activeLabelColor}
                    strokeWidth={2 / scale}
                    closed={false}
                  />
                )}
                {tempPolyline.map((pt, idx) => (
                  <Circle
                    key={idx}
                    x={pt.x}
                    y={pt.y}
                    radius={4 / scale}
                    fill="#fff"
                    stroke={activeLabelColor}
                    strokeWidth={1 / scale}
                  />
                ))}
              </>
            )}

            {/* In-progress Ellipse */}
            {newEllipse && selectedTool === 'ellipse' && (
              <Ellipse
                x={newEllipse.x}
                y={newEllipse.y}
                radiusX={newEllipse.radiusX}
                radiusY={newEllipse.radiusY}
                rotation={newEllipse.rotation}
                fill={activeLabelColor + '55'}
                stroke={activeLabelColor}
                strokeWidth={2 / scale}
              />
            )}

            {/* In-progress Points */}
            {drawingPoint && selectedTool === 'point' && (
              <>
                {tempPointPoints.map((pt, idx) => (
                  <Circle
                    key={idx}
                    x={pt.x}
                    y={pt.y}
                    radius={4 / scale}
                    fill="#fff"
                    stroke={activeLabelColor}
                    strokeWidth={1 / scale}
                  />
                ))}
              </>
            )}

            {/* In-progress Instance Polygon */}
            {drawingInstancePolygon &&
              selectedTool === 'segmentation' &&
              segmentationType === 'instance' && (
                <>
                  {tempInstancePoints.length > 1 && (
                    <Line
                      points={flattenPoints([
                        ...tempInstancePoints,
                        tempInstancePoints[0],
                      ])}
                      fill={activeLabelColor + '55'}
                      stroke={activeLabelColor}
                      strokeWidth={2 / scale}
                      closed
                    />
                  )}
                  {tempInstancePoints.map((pt, idx) => (
                    <Circle
                      key={idx}
                      x={pt.x}
                      y={pt.y}
                      radius={4 / scale}
                      fill="#fff"
                      stroke={activeLabelColor}
                      strokeWidth={1 / scale}
                    />
                  ))}
                </>
              )}

            {/* In-progress Semantic Polygon */}
            {drawingSemanticPolygon &&
              selectedTool === 'segmentation' &&
              segmentationType === 'semantic' && (
                <>
                  {tempSemanticPoints.length > 1 && (
                    <Line
                      points={flattenPoints([
                        ...tempSemanticPoints,
                        tempSemanticPoints[0],
                      ])}
                      fill={activeLabelColor + '55'}
                      stroke={activeLabelColor}
                      strokeWidth={2 / scale}
                      closed
                    />
                  )}
                  {tempSemanticPoints.map((pt, idx) => (
                    <Circle
                      key={idx}
                      x={pt.x}
                      y={pt.y}
                      radius={4 / scale}
                      fill="#fff"
                      stroke={activeLabelColor}
                      strokeWidth={1 / scale}
                    />
                  ))}
                </>
              )}
          </Group>

          {/* Transformer (only for bbox & ellipse) */}
          <Transformer
            ref={transformerRef}
            rotateEnabled={false}
            anchorSize={8}
            borderDash={[6, 2]}
            onTransformEnd={handleTransformEnd}
            onDragEnd={handleTransformEnd}
          />
        </Layer>
      </Stage>
    </div>
  );
});

// A small Konva Label to let user delete a selected annotation
function DeleteLabel({ annotation, scale, shapeBoundingBox, onDelete, color }) {
  const box = shapeBoundingBox(annotation);
  if (!box) return null;

  const xPos = box.x1;
  const yPos = box.y1 - 20 / scale; // 20 px above, scaled

  return (
    <Label
      x={xPos}
      y={yPos}
      onClick={(e) => {
        e.cancelBubble = true;
        onDelete();
      }}
      scaleX={1 / scale}
      scaleY={1 / scale}
    >
      <Tag fill={color || 'red'} opacity={0.8} cornerRadius={4} />
      <Text text="Delete" fill="#fff" padding={5} fontSize={14} />
    </Label>
  );
}

// A small Konva Label to display the instance ID if present
function InstanceIdLabel({ annotation, scale, shapeBoundingBox, color }) {
  const box = shapeBoundingBox(annotation);
  if (!box) return null;
  if (!annotation.instanceId) return null;

  const xPos = box.x1;
  const yPos = box.y1 - 35 / scale; // place slightly above the shape

  return (
    <Label
      x={xPos}
      y={yPos}
      scaleX={1 / scale}
      scaleY={1 / scale}
    >
      <Tag fill={color || '#ff0000'} opacity={0.9} cornerRadius={4} />
      <Text text={annotation.instanceId} fill="#fff" padding={5} fontSize={14} />
    </Label>
  );
}
